module.exports = async function (data) {
  const { services } = data;
  const { ItemsService } = services;

  const body = data?.$trigger?.body || data?.trigger?.body || {};
  const userId = body.user_id;

  if (!userId) {
    throw new Error('Missing user_id in trigger body');
  }

  const quizService = new ItemsService('quiz_attempts', { accountability: data.accountability });
  const ledgerService = new ItemsService('points_ledger', { accountability: data.accountability });

  // Read Data ist der Step direkt davor → liegt typischerweise in data.last
  const attempts = Array.isArray(data.last) ? data.last : (data.last?.data ?? []);

  let claimed = 0;

  for (const attempt of attempts) {
    // defensive checks
    if (!attempt?.id) continue;
    if (!attempt?.eligible_points) continue;

    // 1) attempt markieren (user + claimed_at)
    await quizService.updateOne(attempt.id, {
      user: userId,
      points_claimed_at: new Date().toISOString()
    });

    // 2) ledger schreiben
    const ledgerId = await ledgerService.createOne({
      user: userId,
      points_delta: attempt.eligible_points,
      source_type: 'education',
      source_ref: `quiz_attempts:${attempt.id}`,
      rule_version: 'v1',
      occurred_at: new Date().toISOString()
    });

    // 3) ledger ref zurück ins attempt
    await quizService.updateOne(attempt.id, {
      points_ledger_ref: ledgerId
    });

    claimed += 1;
  }

  return { claimed };
};

module.exports = async function(data) {
  const recentEntries = data.read_recent_steps || [];
  const newDate = data.validate_input.date;
  const userId = data.validate_input.user_id;

  // Alle eingetragenen Daten extrahieren (aus meta.date)
  const enteredDates = new Set();
  enteredDates.add(newDate); // heutiger Eintrag mitzählen

  for (const entry of recentEntries) {
    if (entry.meta && entry.meta.date) {
      enteredDates.add(entry.meta.date);
    }
  }

  // Streak berechnen: rückwärts vom neuen Datum prüfen ob aufeinanderfolgende Tage
  let streak = 0;
  const checkDate = new Date(newDate);

  while (true) {
    const dateStr = checkDate.toISOString().split('T')[0];
    if (enteredDates.has(dateStr)) {
      streak++;
      checkDate.setDate(checkDate.getDate() - 1);
    } else {
      break;
    }
    if (streak > 365) break; // Sicherheits-Stopp
  }

  // Streak-Bonus: bei 7 Tagen (und Vielfachen davon)
  const streakBonusAwarded = streak > 0 && streak % 7 === 0;

  return {
    streak_days: streak,
    streak_bonus_awarded: streakBonusAwarded,
    streak_bonus_punkte: streakBonusAwarded ? 60 : 0
  };
}

module.exports = async function(data) {
  // Abbrechen wenn bereits eingetragen
  if (data.duplicate_check.skipped) {
    return { punkte: 0, skipped: true };
  }

  const steps = data.validate_input.steps;
  let punkte = 0;

  // Punkte-Formel (konsistent mit Frontend-Vorschau)
  if (steps >= 4000 && steps < 7000) {
    punkte = 10;
  } else if (steps >= 7000) {
    punkte = 40;
    // Bonus über Tagesziel: +5P pro 500 Schritte über 7.000
    const extraSteps = steps - 7000;
    const extraPunkte = Math.floor(extraSteps / 500) * 5;
    punkte += extraPunkte;
  }
  // < 4.000 Schritte → 0P (kein Eintrag nötig)

  return {
    punkte: punkte,
    steps: steps,
    skipped: punkte === 0
  };
}

